1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	};
9	
10	export function quote(input: any): unknown {
11	  const itemsBase = input.items.reduce(
12	    (sum: number, item: any) => sum + (BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0),
13	    0
14	  );
15	  return { premium: itemsBase + PROCESSING_FEE };
16	}
